<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">template = template.replace(</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;SYS&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;SYSTEM&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)  </span><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 修改系统标记</span></span>
